df = pd.DataFrame.from_dict(list(results))

min_total_loss = df.groupby(parameter)['total_test_loss'].min()
min_markov_loss = df.groupby(parameter)['markov_test_loss'].min()
min_behaviour_loss = df.groupby(parameter)['behaviour_test_loss'].min()

plt.figure(figsize=(10, 6))
plt.plot(min_total_loss, label='total loss')
plt.plot(min_markov_loss, label='markov loss')
plt.plot(min_behaviour_loss, label='behaviour loss')
plt.legend()
plt.xlabel(parameter)
plt.ylabel('Loss')
plt.title(f'Markov and Behaviour Loss vs {parameter}')
plt.show()


df_melted = df.melt(id_vars=parameter,
                    value_vars=['markov_test_loss', 'behaviour_test_loss', 'total_test_loss'],
                    var_name='Loss Type',
                    value_name='Loss')
plt.figure(figsize=(10, 6))
sns.stripplot(
    data=df_melted,
    x=parameter,
    y='Loss',
    hue='Loss Type',
    )

plt.xlabel(parameter)
plt.ylabel('Loss')
plt.title(f'markov and behaviour loss vs {parameter}')
